using namespace Lexilla;

namespace {

//KeywordIndex++Autogenerated -- start of section automatically generated
enum {
	KeywordIndex_Keyword = 0,
	KeywordIndex_TypeKeyword = 1,
	MaxKeywordSize = 20,
};
//KeywordIndex--Autogenerated -- end of section automatically generated

// https://docs.appeon.com/pb2025/powerscript_reference/xREF_36556_Special_ASCII.html
struct EscapeSequence {
	int outerState = SCE_POWERBUILDER_DEFAULT;
	int digitsLeft = 0;
	bool hex = false;

	// highlight any character as escape sequence.
	bool resetEscapeState(int state, int chNext) noexcept {
		if (IsEOLChar(chNext)) {
			return false;
		}
		outerState = state;
		digitsLeft = 1;
		hex = false;
		if (chNext == 'h') {
			digitsLeft = 4;
			hex = true;
		} else if (chNext == 'o') {
			digitsLeft = 5;
		} else if (IsADigit(chNext)) {
			digitsLeft = 4;
		}
		return true;
	}
	bool atEscapeEnd(int ch) noexcept {
		--digitsLeft;
		return digitsLeft <= 0 || !IsOctalOrHex(ch, hex);
	}
};

constexpr bool IsPbIdentifierChar(int ch) noexcept {
	return IsIdentifierChar(ch) || AnyOf(ch, '-', '$', '#', '%');
}

constexpr bool IsDateTimeStart(int ch, int chNext) noexcept {
	return AnyOf(ch, ':', '-', ' ') && IsADigit(chNext);
}

constexpr bool IsDateTimeChar(int ch, int chNext) noexcept {
	return IsADigit(ch) || (AnyOf(ch, ':', '-', ' ', '.') && IsADigit(chNext));
}

constexpr bool IsMultilineStyle(int style) noexcept {
	return style == SCE_POWERBUILDER_COMMENTBLOCK
		|| (style >= SCE_POWERBUILDER_COMMENTBLOCK && style <= SCE_POWERBUILDER_ESCAPECHAR);
}

void ColourisePowerBuilderDoc(Sci_PositionU startPos, Sci_Position lengthDoc, int initStyle, LexerWordList keywordLists, Accessor &styler) {
	unsigned lineState = 0;
	int indentCount = 0;
	int commentLevel = 0;
	int visibleChars = 0;
	EscapeSequence escSeq;
	bool preprocessor = false;

	StyleContext sc(startPos, lengthDoc, initStyle, styler);
	if (sc.currentLine > 0) {
		lineState = styler.GetLineState(sc.currentLine - 1);
		commentLevel = (lineState >> 8) & 0xff;
		lineState &= PyLineStateLineContinuation;
	}

	while (sc.More()) {
		switch (sc.state) {
		case SCE_POWERBUILDER_OPERATOR:
			sc.SetState(SCE_POWERBUILDER_DEFAULT);
			break;

		case SCE_POWERBUILDER_NUMBER:
			if (!IsDecimalNumber(sc.chPrev, sc.ch, sc.chNext)) {
				if (IsDateTimeStart(sc.ch, sc.chNext)) {
					sc.ChangeState(SCE_POWERBUILDER_DATETIME);
				} else {
					sc.SetState(SCE_POWERBUILDER_DEFAULT);
				}
			}
			break;

		case SCE_POWERBUILDER_DATETIME:
			if (!IsDateTimeChar(sc.ch, sc.chNext)) {
				sc.SetState(SCE_POWERBUILDER_DEFAULT);
			}
			break;

		case SCE_POWERBUILDER_STRING_SQ:
		case SCE_POWERBUILDER_STRING_DQ:
			if (sc.atLineStart) {
				if (lineState == PyLineStateLineContinuation) {
					lineState = 0;
				} else {
					sc.SetState(SCE_POWERBUILDER_DEFAULT);
					break;
				}
			}
			if (sc.ch == '~' && escSeq.resetEscapeState(sc.state, sc.chNext)) {
				sc.SetState(SCE_POWERBUILDER_ESCAPECHAR);
				sc.Forward();
			} else if ((sc.ch == '\'' && sc.state == SCE_POWERBUILDER_STRING_SQ) || (sc.ch == '\"' && sc.state == SCE_POWERBUILDER_STRING_DQ)) {
				sc.ForwardSetState(SCE_POWERBUILDER_DEFAULT);
			} else if (sc.ch == '&' && sc.GetLineNextChar(true) == '\0') {
				escSeq.outerState = sc.state;
				lineState = PyLineStateLineContinuation;
				sc.SetState(SCE_POWERBUILDER_LINE_CONTINUATION);
				sc.ForwardSetState(escSeq.outerState);
			}
			break;

		case SCE_POWERBUILDER_ESCAPECHAR:
			if (escSeq.atEscapeEnd(sc.ch)) {
				sc.SetState(escSeq.outerState);
				continue;
			}
			break;

		case SCE_POWERBUILDER_IDENTIFIER:
		case SCE_POWERBUILDER_PARAMETER:
		case SCE_POWERBUILDER_VARIABLE:
		case SCE_POWERBUILDER_PREPROCESSOR:
			if (!IsPbIdentifierChar(sc.ch)) {
				if (sc.state == SCE_POWERBUILDER_IDENTIFIER || sc.state == SCE_POWERBUILDER_PREPROCESSOR) {
					char s[MaxKeywordSize];
					sc.GetCurrentLowered(s, sizeof(s));
					if (sc.state == SCE_POWERBUILDER_IDENTIFIER) {
						if (keywordLists[KeywordIndex_Keyword].InList(s)) {
							sc.ChangeState(preprocessor ? SCE_POWERBUILDER_PREPROCESSOR_WORD : SCE_POWERBUILDER_KEYWORD);
						} else if (keywordLists[KeywordIndex_TypeKeyword].InList(s)) {
							sc.ChangeState(SCE_POWERBUILDER_TYPE);
						} else if (sc.ch == ':' && sc.chNext != ':' && visibleChars == sc.LengthCurrent()) {
							sc.ChangeState(SCE_POWERBUILDER_LABEL);
						} else {
							const int chNext = sc.GetLineNextChar();
							if (chNext == '(') {
								sc.ChangeState(SCE_POWERBUILDER_FUNCTION);
							} else if (visibleChars == sc.LengthCurrent() && IsIdentifierStart(chNext)) {
								sc.ChangeState(SCE_POWERBUILDER_TYPE);
							}
						}
					}
					const int offset = (sc.state == SCE_POWERBUILDER_PREPROCESSOR) ? 1 : 0;
					if (visibleChars == 3 + offset && StrEqual(s + offset, "end")) {
						lineState |= PyLineStateMaskCloseBrace;
					}
				}
				sc.SetState(SCE_POWERBUILDER_DEFAULT);
			}
			break;

		case SCE_POWERBUILDER_COMMENTLINE:
			if (sc.atLineStart) {
				sc.SetState(SCE_POWERBUILDER_DEFAULT);
			}
			break;

		case SCE_POWERBUILDER_COMMENTBLOCK:
			if (sc.Match('/', '*')) {
				++commentLevel;
				sc.Forward();
			} else if (sc.Match('*', '/')) {
				sc.Forward();
				--commentLevel;
				if (commentLevel == 0) {
					sc.ForwardSetState(SCE_POWERBUILDER_DEFAULT);
				}
			}
			break;
		}

		if (sc.state == SCE_POWERBUILDER_DEFAULT) {
			if (sc.Match('/', '/')) {
				sc.SetState(SCE_POWERBUILDER_COMMENTLINE);
				if (visibleChars == 0) {
					lineState = PyLineStateMaskCommentLine;
				}
			} else if (sc.Match('/', '*')) {
				commentLevel = 1;
				sc.SetState(SCE_POWERBUILDER_COMMENTBLOCK);
				sc.Forward();
			} else if (sc.ch == '\"') {
				sc.SetState(SCE_POWERBUILDER_STRING_DQ);
			} else if (sc.ch == '\'') {
				sc.SetState(SCE_POWERBUILDER_STRING_SQ);
			} else if (IsNumberStartEx(sc.chPrev, sc.ch, sc.chNext)) {
				sc.SetState(SCE_POWERBUILDER_NUMBER);
			} else if (IsIdentifierStart(sc.ch)) {
				sc.SetState(SCE_POWERBUILDER_IDENTIFIER);
			} else if ((sc.ch == '@' || (sc.ch == ':' && sc.chPrev != ':')) && IsIdentifierStart(sc.chNext)) {
				sc.SetState(sc.ch == '@' ? SCE_POWERBUILDER_PARAMETER : SCE_POWERBUILDER_VARIABLE);
			} else if (sc.ch == '#' && visibleChars == 0 && IsAlpha(sc.chNext)) {
				preprocessor = true;
				sc.SetState(SCE_POWERBUILDER_PREPROCESSOR);
			} else if (IsAGraphic(sc.ch)) {
				sc.SetState(SCE_POWERBUILDER_OPERATOR);
				if (visibleChars == 0 && (sc.ch == '}' || sc.ch == ']' || sc.ch == ')')) {
					lineState |= PyLineStateMaskCloseBrace;
				}
			}
		}

		if (visibleChars == 0) {
			if (sc.ch == ' ') {
				++indentCount;
			} else if (sc.ch == '\t') {
				indentCount = GetTabIndentCount(indentCount);
			}
		}
		if (!isspacechar(sc.ch)) {
			visibleChars++;
		}
		if (sc.atLineEnd) {
			lineState |= (commentLevel << 8) | (indentCount << 16);
			if (IsMultilineStyle(sc.state)) {
				lineState |= PyLineStateMaskTripleQuote;
			} else if (visibleChars == 0) {
				lineState |= PyLineStateMaskEmptyLine;
			}
			styler.SetLineState(sc.currentLine, lineState);
			lineState &= PyLineStateLineContinuation;
			visibleChars = 0;
			indentCount = 0;
			preprocessor = false;
		}
		sc.Forward();
	}

	sc.Complete();
}

}

extern const LexerModule lmPowerBuilder(SCLEX_POWERBUILDER, ColourisePowerBuilderDoc, "powerbuilder", FoldPyDoc);
